#!/usr/bin/env node
// Continuous-batch GPU throughput gate (a measurement harness, NOT a deploy).
//
// Fires requests at a fat-station /generate and measures aggregate decode tok/s at
// several concurrency levels, using CLIENT-side wall time (the server/CF timers
// coarsen — see the vGPU notes). Against ONE url it reports, per K:
//   serial-K   : K requests back-to-back   → aggregate tok/s (the serial baseline)
//   concurrent-K: K requests in parallel    → aggregate tok/s
//   speedup     = concurrent-K / serial-K
//
// Interpretation (the gate):
//   flag OFF (Mutex serialize-all): concurrent-K ≈ serial-K   → speedup ≈ 1.0
//   flag ON  (MOONSHINE_CONTINUOUS_BATCH): concurrent-K > serial-K, speedup climbing
//     toward K until the KV arena / GPU SM saturates — the realized analogue of
//     prefill's measured 6.2×. Run it against a flag-OFF rev and a flag-ON canary and
//     compare; a single flag-ON run should already show speedup > 1.
//
// Usage:
//   node continuous-batch-throughput-gate.mjs \
//     --url http://localhost:8000 [--k 1,2,4,8] [--max-new 64] [--prompt-len 64] \
//     [--tokens 1,2,3,...] [--temperature 0] [--label flag-on]
//
// Coherence: pass --tokens with a real prompt's token ids and eyeball the first lane's
// generated_tokens (decode them with your tokenizer) for the "Paris…"-class sanity check.

function parseArgs(argv) {
  const a = {};
  for (let i = 0; i < argv.length; i++) {
    if (argv[i].startsWith('--')) {
      const key = argv[i].slice(2);
      const val = argv[i + 1] && !argv[i + 1].startsWith('--') ? argv[++i] : 'true';
      a[key] = val;
    }
  }
  return a;
}

const args = parseArgs(process.argv.slice(2));
const URL = args.url || process.env.STATION_URL || 'http://localhost:8000';
const KS = (args.k || '1,2,4,8').split(',').map((s) => parseInt(s, 10)).filter((n) => n > 0);
const MAX_NEW = parseInt(args['max-new'] || '64', 10);
const TEMPERATURE = parseFloat(args.temperature || '0');
const LABEL = args.label || '';
// Prompt: explicit --tokens wins; else a synthetic prompt of --prompt-len smallish ids.
const PROMPT = args.tokens
  ? args.tokens.split(',').map((s) => parseInt(s, 10))
  : Array.from({ length: parseInt(args['prompt-len'] || '64', 10) }, (_, i) => (i % 100) + 5);

async function oneGenerate() {
  const t0 = Date.now();
  const res = await fetch(`${URL}/generate`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ tokens: PROMPT, max_new_tokens: MAX_NEW, temperature: TEMPERATURE }),
  });
  if (!res.ok) {
    throw new Error(`/generate ${res.status}: ${(await res.text()).slice(0, 200)}`);
  }
  const j = await res.json();
  const n = j.num_new_tokens ?? (j.generated_tokens ? j.generated_tokens.length : 0);
  return { tokens: n, wallMs: Date.now() - t0, first: (j.generated_tokens || []).slice(0, 8) };
}

// Aggregate tok/s = total generated tokens / wall-clock span of the whole batch.
async function measure(k, mode) {
  const t0 = Date.now();
  let total = 0;
  let sample = null;
  if (mode === 'serial') {
    for (let i = 0; i < k; i++) {
      const r = await oneGenerate();
      total += r.tokens;
      if (!sample) sample = r.first;
    }
  } else {
    const rs = await Promise.all(Array.from({ length: k }, () => oneGenerate()));
    for (const r of rs) total += r.tokens;
    sample = rs[0].first;
  }
  const wall = (Date.now() - t0) / 1000;
  return { tokPerSec: total / wall, total, wall, sample };
}

async function main() {
  console.log(`# continuous-batch throughput gate${LABEL ? ` [${LABEL}]` : ''}`);
  console.log(`# url=${URL} prompt_len=${PROMPT.length} max_new=${MAX_NEW} temp=${TEMPERATURE}`);
  // Warm the station (cold start / first-fault) before timing.
  try {
    await oneGenerate();
  } catch (e) {
    console.error(`warmup failed: ${e.message}`);
    process.exit(1);
  }
  console.log('K\tserial_tok/s\tconcurrent_tok/s\tspeedup');
  for (const k of KS) {
    const serial = await measure(k, 'serial');
    const conc = await measure(k, 'concurrent');
    const speedup = conc.tokPerSec / serial.tokPerSec;
    console.log(
      `${k}\t${serial.tokPerSec.toFixed(2)}\t\t${conc.tokPerSec.toFixed(2)}\t\t${speedup.toFixed(2)}×`,
    );
    if (k === KS[KS.length - 1]) {
      console.log(`# coherence sample (lane 0 first tokens): [${conc.sample.join(', ')}]`);
    }
  }
  console.log(
    '# gate: flag-OFF → speedup ≈ 1.0 (serialized); flag-ON → speedup > 1, climbing toward K\n' +
      '#       until KV/SM saturates. Run against flag-OFF and flag-ON revs to confirm the win.',
  );
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
